import React, { useState, useEffect } from 'react';
import { getMembers } from '../services/api';
import AddMember from '../components/AddMember';

function Members() {
  const [members, setMembers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchMembers = async () => {
    try {
      const response = await getMembers();
      setMembers(response.data);
      setLoading(false);
    } catch (err) {
      setError('خطأ في جلب الأعضاء');
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMembers();
  }, []);

  if (loading) return <div className="text-center">جاري التحميل...</div>;
  if (error) return <div className="alert alert-danger">{error}</div>;

  return (
    <div>
      <h2 className="mb-4">إدارة الأعضاء</h2>

      {/* نموذج الإضافة */}
      <AddMember onMemberAdded={fetchMembers} />

      {/* قائمة الأعضاء */}
      {members.length === 0 ? (
        <div className="alert alert-info">لا يوجد أعضاء مسجلين بعد</div>
      ) : (
        <div className="table-responsive">
          <table className="table table-striped table-hover">
            <thead className="table-dark">
              <tr>
                <th>الاسم</th>
                <th>اللقب</th>
                <th>العمر</th>
                <th>البريد</th>
                <th>التسجيل</th>
                <th>النوع</th>
              </tr>
            </thead>
            <tbody>
              {members.map((member) => (
                <tr key={member.id_personne}>
                  <td>{member.nom}</td>
                  <td>{member.prenom}</td>
                  <td>{member.age}</td>
                  <td>{member.email}</td>
                  <td>{member.date_inscription}</td>
                  <td>{member.type_membre}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Members;
